          {/* <Link to="About" smooth={true} duration={500}>
            About
          </Link> */}
        {/* </li>
      </ul> */}
    </NavContainer>
  )
}

const NavContainer = styled.nav`
  grid-column: 1/3;
  display: flex;
  justify-content: space-between;
  padding: 2em;

  position: sticky;

  & img {
    filter: invert(1);
    width: 2em;
    height: 2em;
  }
`

const Hamburger = styled.button`
  background: transparent;
  border: 0;
  cursor: pointer;
`

export default Nav
